// ─── Locale map: language code → translations object ─────────────────────────
export const LOCALES: Record<LanguageCode, CalendarTranslations> = {
  tr, en, fr, de, es, it, pt, ar, zh, ja, ko, ru, nl, pl, sv,
};

/**
 * Returns the full translation object for a given language code,
 * merged with any custom override translations.
 */
export function getTranslations(
  language: LanguageCode = 'tr',
  overrides: Partial<CalendarTranslations> = {}
): CalendarTranslations {
  return { ...LOCALES[language], ...overrides };
}
